import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is percent error?", a: "Percent error measures how far an experimental value is from a theoretical or accepted value, expressed as a percentage of the theoretical value. It is commonly used in science labs to evaluate measurement accuracy." },
  { q: "What is the formula for percent error?", a: "Percent Error = (|Experimental - Theoretical| / Theoretical) x 100. The absolute value makes the error size positive, while comparing the original values tells you whether the experiment overestimated or underestimated." },
  { q: "What is a good percent error in science?", a: "A good percent error depends on the experiment. In controlled lab measurements, under 5% is often considered strong. In more complex real-world experiments, 10% or higher may still be acceptable if measurement conditions are difficult." },
  { q: "What is the difference between percent error and percent difference?", a: "Percent error compares a measured value to a known accepted value. Percent difference compares two measured values when neither one is treated as the true value. Percent difference uses the average of the two values as the denominator." },
  { q: "Can percent error be negative?", a: "Standard percent error is usually reported as positive because the formula uses absolute error. If you do not use absolute value, the signed error can be negative when the experimental value is below the theoretical value." },
];

export default function PercentErrorCalculator() {
  const [experimental, setExperimental] = useState(98);
  const [theoretical, setTheoretical] = useState(100);
  const absoluteError = Math.abs(experimental - theoretical);
  const percentError = theoretical !== 0 ? (absoluteError / Math.abs(theoretical)) * 100 : 0;
  const direction = experimental > theoretical ? "Overestimate" : experimental < theoretical ? "Underestimate" : "Exact match";
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead
        title="Free Percent Error Calculator Online - Calculate Experimental Error Instantly | CalcHive"
        description="Free online percent error calculator. Calculate the percent error between any experimental and theoretical value instantly. 100% free for science students and everyone, no signup required."
        canonical="/percent-error-calculator"
        keywords="free percent error calculator, percent error calculator online free, calculate experimental error free, theoretical vs experimental value calculator free, science error calculator free"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Percent Error Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free percent error calculator to calculate experimental error free between theoretical and experimental values.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div>
              <label htmlFor="experimental" className="text-sm font-semibold text-foreground block mb-2">Experimental value</label>
              <input id="experimental" type="number" inputMode="decimal" value={experimental} onChange={(event) => setExperimental(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label htmlFor="theoretical" className="text-sm font-semibold text-foreground block mb-2">Theoretical value</label>
              <input id="theoretical" type="number" inputMode="decimal" value={theoretical} onChange={(event) => setTheoretical(Number(event.target.value))} className={inputClass} />
            </div>
          </div>
          <motion.div key={`${experimental}-${theoretical}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Percent Error</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-percent-error">{Number.isFinite(percentError) ? `${percentError.toFixed(4).replace(/\.?0+$/, "")}%` : "0%"}</p>
              <p className="text-white/70 text-sm mt-1">{direction}</p>
            </div>
            <div className="grid grid-cols-2 gap-3 mt-4">
              <div className="bg-accent/60 border border-border rounded-xl p-3 text-center">
                <p className="text-xs text-muted-foreground font-medium">Absolute Error</p>
                <p className="text-lg font-extrabold text-foreground" data-testid="result-absolute-error">{absoluteError.toLocaleString()}</p>
              </div>
              <div className="bg-accent/60 border border-border rounded-xl p-3 text-center">
                <p className="text-xs text-muted-foreground font-medium">Estimate Type</p>
                <p className="text-lg font-extrabold text-foreground" data-testid="result-direction">{direction}</p>
              </div>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Percent Error for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground">Percent Error = (|Experimental - Theoretical| / Theoretical) x 100</div>
          <h2 className="text-2xl font-bold text-foreground">What the Percent Error Formula Means in Science</h2>
          <p className="text-muted-foreground leading-relaxed">Percent error shows the size of measurement error compared with the accepted value, making it easier to compare experiments with different units or scales.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Experimental Error Calculator for Science Students</h2>
          <p className="text-muted-foreground leading-relaxed">Use this science error calculator free tool for chemistry, physics, biology, and lab reports.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/percent-error-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


